using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains and evaluates the ticket classification model at startup.
/// </summary>
public sealed class ModelTrainingService : IHostedService
{
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        TrainAndEvaluate();
        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;

    private void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        IDataView dataView = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split into train/test sets
        var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text + combine with numeric features â†’ classify
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on the held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _logger.LogInformation("===== Model Evaluation Metrics =====");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("Per-class metrics:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Save the trained model
        mlContext.Model.Save(model, dataView.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class PredictionController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public PredictionController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var categories = new[] { "Billing", "General", "Technical" };
        var confidences = categories
            .Zip(prediction.Score, (cat, score) => new { cat, score })
            .OrderByDescending(x => x.score)
            .ToDictionary(x => x.cat, x => Math.Round(x.score, 4));

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidences
        });
    }
}

public sealed class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, double> Confidence { get; set; } = [];
}

